+          MATCHES_JSON: ${{ steps.parse.outputs.matches }}
+          BRANCH_REF: ${{ steps.branch.outputs.ref }}
+        with:
+          script: |
+            const matches = JSON.parse(process.env.MATCHES_JSON);
+            const ref = process.env.BRANCH_REF;
+            const owner = context.repo.owner;
+            const repo = context.repo.repo;
+
+            const POLL_INTERVAL_MS = 5000;   // 5 seconds between polls
+            const MAX_POLL_ATTEMPTS = 12;     // 60 seconds total max wait
+
+            // Record time before dispatching (used to identify new runs)
+            const beforeDispatch = new Date();
+
+            // Get the HEAD SHA of the branch so we can correlate runs
+            // more precisely than timestamps alone.
+            const { data: refData } = await github.rest.git.getRef({
+              owner, repo,
+              ref: `heads/${ref}`,
+            });
+            const headSha = refData.object.sha;
+
+            // Dispatch all workflows
+            for (const m of matches) {
+              console.log(`Dispatching ${m.workflowFile} on ref ${ref}`);
+              await github.rest.actions.createWorkflowDispatch({
+                owner, repo,
+                workflow_id: m.workflowFile,
+                ref,
+              });
+              m.runUrl = null;
+            }
+
+            // Poll for run URLs — wait for GitHub to create the runs
+            for (let attempt = 0; attempt < MAX_POLL_ATTEMPTS; attempt++) {
+              await new Promise(r => setTimeout(r, POLL_INTERVAL_MS));
+
+              const pending = matches.filter(m => !m.runUrl);
+              if (pending.length === 0) break;
+
+              for (const m of pending) {
+                try {
+                  const { data: { workflow_runs: runs } } = await github.rest.actions.listWorkflowRuns({
+                    owner, repo,
+                    workflow_id: m.workflowFile,
+                    branch: ref,
+                    per_page: 5,
+                  });
+
+                  // Match on head_sha AND creation time to avoid picking
+                  // a run from a different concurrent dispatch.
+                  const newRun = runs.find(r =>
+                    r.head_sha === headSha &&
+                    new Date(r.created_at) >= beforeDispatch
+                  );
+                  if (newRun) {
+                    m.runUrl = newRun.html_url;
+                    console.log(`Found run for ${m.name}: ${m.runUrl}`);
+                  }
+                } catch (e) {
+                  console.log(`Error polling for ${m.name}: ${e.message}`);
+                }
+              }
+            }
+
+            // Log any that were not found
+            for (const m of matches) {
+              if (!m.runUrl) {
+                console.log(`Warning: could not find run URL for ${m.name} after polling`);
+              }
+            }
+
+            core.setOutput('results', JSON.stringify(matches));

